import { GoogleGenAI } from "@google/genai";

const apiKey = process.env.API_KEY || '';

// Safely initialize the AI client
const ai = new GoogleGenAI({ apiKey });

export const generateMascotConcept = async (
  brandName: string,
  industry: string,
  vibe: string
): Promise<string> => {
  if (!apiKey) {
    throw new Error("API Key is missing. Please configure the environment.");
  }

  try {
    const prompt = `
      Act as a world-class mascot branding specialist.
      Generate a creative, bold, and unique mascot character concept for a brand with the following details:

      Brand Name: ${brandName}
      Industry: ${industry}
      Desired Vibe: ${vibe}

      Output format:
      Return a single paragraph (approx 80-100 words).
      Describe the mascot's species/object, physical appearance (colors, clothing, props), and personality traits. 
      Focus on how it visually represents the brand. 
      Do not include intro/outro fluff. 
      Keep the tone energetic and professional.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        temperature: 0.8, // Slightly creative
        maxOutputTokens: 200,
      }
    });

    return response.text || "Could not generate a concept at this time.";
  } catch (error) {
    console.error("Error generating mascot concept:", error);
    throw new Error("Failed to generate concept. Please try again.");
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "font-black uppercase tracking-wider py-3 px-8 transition-all duration-200 border-4 border-black text-sm md:text-base";

  const variants = {
    primary: "bg-mascot-yellow text-mascot-black hover:bg-white shadow-hard hover:shadow-none hover:translate-x-1 hover:translate-y-1",
    secondary: "bg-mascot-black text-white hover:bg-gray-800 shadow-hard hover:shadow-none hover:translate-x-1 hover:translate-y-1",
    outline: "bg-transparent text-mascot-black hover:bg-mascot-black hover:text-white shadow-hard hover:shadow-none hover:translate-x-1 hover:translate-y-1"
  };

  const widthClass = fullWidth ? 'w-full' : '';

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${widthClass} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

