import React, { useState } from 'react';
import { Sparkles, Loader2, Copy } from 'lucide-react';
import { Button } from './Button';
import { generateMascotConcept } from '../services/geminiService';

export const MascotGenerator: React.FC = () => {
  const [brandName, setBrandName] = useState('');
  const [industry, setIndustry] = useState('');
  const [vibe, setVibe] = useState('Energetic');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!brandName || !industry) return;

    setLoading(true);
    setError('');
    setResult('');

    try {
      const concept = await generateMascotConcept(brandName, industry, vibe);
      setResult(concept);
    } catch (err) {
      setError('System overload. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="bg-mascot-gray p-8 border-4 border-black shadow-hard relative overflow-hidden">
      {/* Decorative element */}
      <div className="absolute -top-6 -right-6 w-24 h-24 bg-mascot-yellow border-4 border-black rounded-full z-0"></div>

      <div className="relative z-10">
        <div className="flex items-center gap-2 mb-6">
          <Sparkles className="text-mascot-yellow w-8 h-8 fill-black" strokeWidth={1.5} />
          <h3 className="text-2xl font-black uppercase italic">Mascot Concept Generator</h3>
        </div>

        <p className="mb-6 font-medium text-gray-600">
          Stuck on ideas? Let my AI brainstorming assistant sketch a mental draft for you. 
          Powered by Gemini.
        </p>

        <form onSubmit={handleGenerate} className="space-y-4">
          <div>
            <label className="block font-bold text-sm uppercase mb-1">Brand Name</label>
            <input 
              type="text" 
              value={brandName}
              onChange={(e) => setBrandName(e.target.value)}
              className="w-full p-3 border-2 border-black focus:outline-none focus:ring-4 focus:ring-mascot-yellow transition-all font-bold"
              placeholder="e.g. RocketBurger"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
             <div>
                <label className="block font-bold text-sm uppercase mb-1">Industry</label>
                <input 
                  type="text" 
                  value={industry}
                  onChange={(e) => setIndustry(e.target.value)}
                  className="w-full p-3 border-2 border-black focus:outline-none focus:ring-4 focus:ring-mascot-yellow transition-all font-bold"
                  placeholder="e.g. Fast Food"
                />
             </div>
             <div>
                <label className="block font-bold text-sm uppercase mb-1">Vibe</label>
                <select 
                  value={vibe}
                  onChange={(e) => setVibe(e.target.value)}
                  className="w-full p-3 border-2 border-black focus:outline-none focus:ring-4 focus:ring-mascot-yellow transition-all font-bold bg-white"
                >
                  <option>Energetic</option>
                  <option>Friendly</option>
                  <option>Aggressive</option>
                  <option>Luxury</option>
                  <option>Tech/Futuristic</option>
                </select>
             </div>
          </div>

          <Button type="submit" fullWidth disabled={loading}>
            {loading ? (
              <span className="flex items-center justify-center gap-2">
                <Loader2 className="animate-spin" /> Brainstorming...
              </span>
            ) : (
              "Generate Concept"
            )}
          </Button>
        </form>

        {error && (
            <div className="mt-4 p-4 bg-red-100 border-2 border-red-500 font-bold text-red-900">
                {error}
            </div>
        )}

        {result && (
          <div className="mt-8 bg-white border-2 border-black p-4 shadow-hard-sm animate-fade-in">
            <h4 className="font-black uppercase text-sm text-gray-400 mb-2 flex justify-between items-center">
                Concept Draft
                <Copy className="w-4 h-4 cursor-pointer hover:text-mascot-yellow" onClick={() => navigator.clipboard.writeText(result)} />
            </h4>
            <p className="font-medium text-lg leading-relaxed">{result}</p>
          </div>
        )}
      </div>
    </div>
  );
};

