import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline';
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  fullWidth = false,
  className = '',
  ...props 
}) => {
  const baseStyles = "font-bold uppercase tracking-wide py-3 px-8 transition-all duration-300 border-2 border-mascot-black text-sm md:text-base rounded-2xl";

  const variants = {
    primary: "bg-mascot-yellow text-mascot-black hover:bg-white shadow-hard hover:shadow-none hover:translate-x-[2px] hover:translate-y-[2px]",
    secondary: "bg-mascot-black text-white hover:bg-gray-800 shadow-hard hover:shadow-none hover:translate-x-[2px] hover:translate-y-[2px]",
    outline: "bg-transparent text-mascot-black hover:bg-mascot-black hover:text-white shadow-hard hover:shadow-none hover:translate-x-[2px] hover:translate-y-[2px]"
  };

  const widthClass = fullWidth ? 'w-full' : '';

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${widthClass} ${className}`}
      {...props}
    >
      {children}
    </button>
  );
};

